import express from "express";
import userController from "../controllers/userController";
import registerLoginController from "../controllers/registerLoginController";

const router = express.Router();

const adminRoute = (app) => {
  // login and register
  router.post("/register", registerLoginController.registerUser);
  // router.get("/login", userController.loginUser);

  // user
  router.get("/", userController.readFunc);
  router.post("/", userController.createFunc);
  router.put("/", userController.createFunc);
  router.delete("/", userController.deleteFunc);
  return app.use("/api/v1", router);
};

export default adminRoute;

